+    }
+
+    // Set budget to 4MB
+    let mut config = RetentionConfig::default();
+    config.disk_budget_bytes = 4 * 1024 * 1024;
+    config.event_log_dir = Some(root.join("retention_logs"));
+
+    let mut enforcer =
